263	template <ENCODING enc>
264	struct Buffer {
265	    char *buf;
266	    char *after;
267	
268	    inline Buffer()
269	    {
270	        buf = after = NULL;
271	    }
272	
273	    inline Buffer(char *buf_, npy_int64 elsize_)
274	    {
275	        buf = buf_;
276	        after = buf_ + elsize_;
277	    }
278	
279	    inline size_t
280	    num_codepoints()
281	    {
282	        Buffer tmp(after, 0);
283	        size_t num_codepoints;
284	        switch (enc) {
285	            case ENCODING::ASCII:
286	            case ENCODING::UTF32:
287	            {
288	                tmp--;
289	                while (tmp >= *this && *tmp == '\0') {
290	                    tmp--;
291	                }
292	                num_codepoints = (size_t) (tmp - *this + 1);
293	                break;
294	            }
295	            case ENCODING::UTF8:
296	            {
297	                num_codepoints_for_utf8_bytes((unsigned char *)buf, &num_codepoints, (size_t)(after - buf));
298	            }
299	        }
300	        return num_codepoints;
301	    }
302	
303	    inline size_t
304	    buffer_width()
305	    {
306	        switch (enc) {
307	            case ENCODING::ASCII:
308	            case ENCODING::UTF8:
309	                return after - buf;
310	            case ENCODING::UTF32:
311	                return (after - buf) / sizeof(npy_ucs4);
312	        }
313	    }
314	
315	    inline Buffer<enc>&
316	    operator+=(npy_int64 rhs)
317	    {
318	        switch (enc) {
319	        case ENCODING::ASCII:
320	            buf += rhs;
321	            break;
322	        case ENCODING::UTF32:
323	            buf += rhs * sizeof(npy_ucs4);
324	            break;
325	        case ENCODING::UTF8:
326	            for (int i=0; i<rhs; i++) {
327	                buf += num_bytes_for_utf8_character((unsigned char *)buf);
328	            }
329	            break;
330	        }
331	        return *this;
332	    }
333	
334	    inline Buffer<enc>&
335	    operator-=(npy_int64 rhs)
336	    {
337	        switch (enc) {
338	        case ENCODING::ASCII:
339	            buf -= rhs;
340	            break;
341	        case ENCODING::UTF32:
342	            buf -= rhs * sizeof(npy_ucs4);
343	            break;
344	        case ENCODING::UTF8:
345	            buf = (char *) find_previous_utf8_character((unsigned char *)buf, (size_t) rhs);
346	        }
347	        return *this;
348	    }
349	
350	    inline Buffer<enc>&
351	    operator++()
352	    {
353	        *this += 1;
354	        return *this;
355	    }
356	
357	    inline Buffer<enc>
358	    operator++(int)
359	    {
360	        Buffer<enc> old = *this;
361	        operator++();
362	        return old;
363	    }
364	
365	    inline Buffer<enc>&
366	    operator--()
367	    {
368	        *this -= 1;
369	        return *this;
370	    }
371	
372	    inline Buffer<enc>
373	    operator--(int)
374	    {
375	        Buffer<enc> old = *this;
376	        operator--();
377	        return old;
378	    }
379	
380	    inline npy_ucs4
381	    operator*()
382	    {
383	        int bytes;
384	        return getchar<enc>((unsigned char *) buf, &bytes);
385	    }
386	
387	    inline int
388	    buffer_memcmp(Buffer<enc> other, size_t len)
389	    {
390	        if (len == 0) {
391	            return 0;
392	        }
393	        switch (enc) {
394	            case ENCODING::ASCII:
395	            case ENCODING::UTF8:
396	                // note that len is in bytes for ASCII and UTF8 but
397	                // characters for UTF32
398	                return memcmp(buf, other.buf, len);
399	            case ENCODING::UTF32:
400	                return memcmp(buf, other.buf, len * sizeof(npy_ucs4));
401	        }
402	    }
403	
404	    inline void
405	    buffer_memcpy(Buffer<enc> other, size_t len)
406	    {
407	        if (len == 0) {
408	            return;
409	        }
410	        switch (enc) {
411	            case ENCODING::ASCII:
412	            case ENCODING::UTF8:
413	                // for UTF8 we treat n_chars as number of bytes
414	                memcpy(other.buf, buf, len);
415	                break;
416	            case ENCODING::UTF32:
417	                memcpy(other.buf, buf, len * sizeof(npy_ucs4));
418	                break;
419	        }
420	    }
421	
422	    inline npy_intp
423	    buffer_memset(npy_ucs4 fill_char, size_t n_chars)
424	    {
425	        if (n_chars == 0) {
426	            return 0;
427	        }
428	        switch (enc) {
429	            case ENCODING::ASCII:
430	                memset(this->buf, fill_char, n_chars);
431	                return n_chars;
432	            case ENCODING::UTF32:
433	            {
434	                char *tmp = this->buf;
435	                for (size_t i = 0; i < n_chars; i++) {
436	                    *(npy_ucs4 *)tmp = fill_char;
437	                    tmp += sizeof(npy_ucs4);
438	                }
439	                return n_chars;
440	            }
441	            case ENCODING::UTF8:
442	            {
443	                char utf8_c[4] = {0};
444	                char *tmp = this->buf;
445	                size_t num_bytes = ucs4_code_to_utf8_char(fill_char, utf8_c);
446	                for (size_t i = 0; i < n_chars; i++) {
447	                    memcpy(tmp, utf8_c, num_bytes);
448	                    tmp += num_bytes;
449	                }
450	                return num_bytes * n_chars;
451	            }
452	        }
453	    }
454	
455	    inline void
456	    buffer_fill_with_zeros_after_index(size_t start_index)
457	    {
458	        Buffer<enc> offset = *this + start_index;
459	        for (char *tmp = offset.buf; tmp < after; tmp++) {
460	            *tmp = 0;
461	        }
462	    }
463	
464	    inline void
465	    advance_chars_or_bytes(size_t n) {
466	        switch (enc) {
467	            case ENCODING::ASCII:
468	            case ENCODING::UTF32:
469	                *this += n;
470	                break;
471	            case ENCODING::UTF8:
472	                this->buf += n;
473	                break;
474	        }
475	    }
476	
477	    inline size_t
478	    num_bytes_next_character() {
479	        switch (enc) {
480	            case ENCODING::ASCII:
481	                return 1;
482	            case ENCODING::UTF32:
483	                return 4;
484	            case ENCODING::UTF8:
485	                return num_bytes_for_utf8_character((unsigned char *)(*this).buf);
486	        }
487	    }
488	
489	    template<IMPLEMENTED_UNARY_FUNCTIONS f>
490	    inline bool
491	    unary_loop()
492	    {
493	        size_t len = num_codepoints();
494	        if (len == 0) {
495	            return false;
496	        }
497	
498	        Buffer<enc> tmp = *this;
499	
500	        for (size_t i=0; i<len; i++) {
501	            bool result;
502	
503	            call_buffer_member_function<f, enc, bool> cbmf;
504	
505	            result = cbmf(tmp);
506	
507	            if (!result) {
508	                return false;
509	            }
510	            tmp++;
511	        }
512	        return true;
513	    }
514	
515	    inline bool
516	    isalpha()
517	    {
518	        return unary_loop<IMPLEMENTED_UNARY_FUNCTIONS::ISALPHA>();
519	    }
520	
521	    inline bool
522	    isdecimal()
523	    {
524	        return unary_loop<IMPLEMENTED_UNARY_FUNCTIONS::ISDECIMAL>();
525	    }
526	
527	    inline bool
528	    isdigit()
529	    {
530	        return unary_loop<IMPLEMENTED_UNARY_FUNCTIONS::ISDIGIT>();
531	    }
532	
533	    inline bool
534	    first_character_isspace()
535	    {
536	        switch (enc) {
537	            case ENCODING::ASCII:
538	                return NumPyOS_ascii_isspace(**this);
539	            case ENCODING::UTF32:
540	            case ENCODING::UTF8:
541	                return Py_UNICODE_ISSPACE(**this);
542	        }
543	    }
544	
545	    inline bool
546	    isspace()
547	    {
548	        return unary_loop<IMPLEMENTED_UNARY_FUNCTIONS::ISSPACE>();
549	    }
550	
551	    inline bool
552	    isalnum()
553	    {
554	        return unary_loop<IMPLEMENTED_UNARY_FUNCTIONS::ISALNUM>();
555	    }
556	
557	    inline bool
558	    islower()
559	    {
560	        size_t len = num_codepoints();
561	        if (len == 0) {
562	            return false;
563	        }
564	
565	        Buffer<enc> tmp = *this;
566	        bool cased = false;
567	        for (size_t i = 0; i < len; i++) {
568	            if (codepoint_isupper<enc>(*tmp) || codepoint_istitle<enc>(*tmp)) {
569	                return false;
570	            }
571	            else if (!cased && codepoint_islower<enc>(*tmp)) {
572	                cased = true;
573	            }
574	            tmp++;
575	        }
576	        return cased;
577	    }
578	
579	    inline bool
580	    isupper()
581	    {
582	        size_t len = num_codepoints();
583	        if (len == 0) {
584	            return false;
585	        }
586	
587	        Buffer<enc> tmp = *this;
588	        bool cased = false;
589	        for (size_t i = 0; i < len; i++) {
590	            if (codepoint_islower<enc>(*tmp) || codepoint_istitle<enc>(*tmp)) {
591	                return false;
592	            }
593	            else if (!cased && codepoint_isupper<enc>(*tmp)) {
594	                cased = true;
595	            }
596	            tmp++;
597	        }
598	        return cased;
599	    }
600	
601	    inline bool
602	    istitle()
603	    {
604	        size_t len = num_codepoints();
605	        if (len == 0) {
606	            return false;
607	        }
608	
609	        Buffer<enc> tmp = *this;
610	        bool cased = false;
611	        bool previous_is_cased = false;
612	        for (size_t i = 0; i < len; i++) {
613	            if (codepoint_isupper<enc>(*tmp) || codepoint_istitle<enc>(*tmp)) {
614	                if (previous_is_cased) {
615	                    return false;
616	                }
617	                previous_is_cased = true;
618	                cased = true;
619	            }
620	            else if (codepoint_islower<enc>(*tmp)) {
621	                if (!previous_is_cased) {
622	                    return false;
623	                }
624	                cased = true;
625	            }
626	            else {
627	                previous_is_cased = false;
628	            }
629	            tmp++;
630	        }
631	        return cased;
632	    }
633	
634	    inline bool
635	    isnumeric()
636	    {
637	        return unary_loop<IMPLEMENTED_UNARY_FUNCTIONS::ISNUMERIC>();
638	    }
639	
640	    inline Buffer<enc>
641	    rstrip()
642	    {
643	        Buffer<enc> tmp(after, 0);
644	        tmp--;
645	        while (tmp >= *this && (
646	                NumPyOS_ascii_isspace(*tmp) ||
647	                (enc != ENCODING::UTF8 && *tmp == '\0'))) {
648	            tmp--;
649	        }
650	        tmp++;
651	
652	        after = tmp.buf;
653	        return *this;
654	    }
655	
656	    inline int
657	    strcmp(Buffer<enc> other, bool rstrip)
658	    {
659	        Buffer tmp1 = rstrip ? this->rstrip() : *this;
660	        Buffer tmp2 = rstrip ? other.rstrip() : other;
661	
662	        while (tmp1.buf < tmp1.after && tmp2.buf < tmp2.after) {
663	            if (*tmp1 < *tmp2) {
664	                return -1;
665	            }
666	            if (*tmp1 > *tmp2) {
667	                return 1;
668	            }
669	            tmp1++;
670	            tmp2++;
671	        }
672	        while (tmp1.buf < tmp1.after) {
673	            if (*tmp1) {
674	                return 1;
675	            }
676	            tmp1++;
677	        }
678	        while (tmp2.buf < tmp2.after) {
679	            if (*tmp2) {
680	                return -1;
681	            }
682	            tmp2++;
683	        }
684	        return 0;
685	    }
686	
687	    inline int
688	    strcmp(Buffer<enc> other)
689	    {
690	        return strcmp(other, false);
691	    }
692	};
