695	template <IMPLEMENTED_UNARY_FUNCTIONS f, ENCODING enc, typename T>
696	struct call_buffer_member_function {
697	    T operator()(Buffer<enc> buf) {
698	        switch (f) {
699	            case IMPLEMENTED_UNARY_FUNCTIONS::ISALPHA:
700	                return codepoint_isalpha<enc>(*buf);
701	            case IMPLEMENTED_UNARY_FUNCTIONS::ISDIGIT:
702	                return codepoint_isdigit<enc>(*buf);
703	            case IMPLEMENTED_UNARY_FUNCTIONS::ISSPACE:
704	                return codepoint_isspace<enc>(*buf);
705	            case IMPLEMENTED_UNARY_FUNCTIONS::ISALNUM:
706	                return codepoint_isalnum<enc>(*buf);
707	            case IMPLEMENTED_UNARY_FUNCTIONS::ISNUMERIC:
708	                return codepoint_isnumeric(*buf);
709	            case IMPLEMENTED_UNARY_FUNCTIONS::ISDECIMAL:
710	                return codepoint_isdecimal(*buf);
711	        }
712	    }
713	};
