715	template <ENCODING enc>
716	inline Buffer<enc>
717	operator+(Buffer<enc> lhs, npy_int64 rhs)
718	{
719	    switch (enc) {
720	        case ENCODING::ASCII:
721	            return Buffer<enc>(lhs.buf + rhs, lhs.after - lhs.buf - rhs);
722	        case ENCODING::UTF32:
723	            return Buffer<enc>(lhs.buf + rhs * sizeof(npy_ucs4),
724	                          lhs.after - lhs.buf - rhs * sizeof(npy_ucs4));
725	        case ENCODING::UTF8:
726	            char* buf = lhs.buf;
727	            for (int i=0; i<rhs; i++) {
728	                buf += num_bytes_for_utf8_character((unsigned char *)buf);
729	            }
730	            return Buffer<enc>(buf, (npy_int64)(lhs.after - buf));
731	    }
732	}
