735	template <ENCODING enc>
736	inline std::ptrdiff_t
737	operator-(Buffer<enc> lhs, Buffer<enc> rhs)
738	{
739	    switch (enc) {
740	    case ENCODING::ASCII:
741	    case ENCODING::UTF8:
742	        // note for UTF8 strings this is nonsense unless we're comparing
743	        // two points in the same string
744	        return lhs.buf - rhs.buf;
745	    case ENCODING::UTF32:
746	        return (lhs.buf - rhs.buf) / (std::ptrdiff_t) sizeof(npy_ucs4);
747	    }
748	}
