752	inline Buffer<enc>
753	operator-(Buffer<enc> lhs, npy_int64 rhs)
754	{
755	    switch (enc) {
756	        case ENCODING::ASCII:
757	            return Buffer<enc>(lhs.buf - rhs, lhs.after - lhs.buf + rhs);
758	        case ENCODING::UTF32:
759	            return Buffer<enc>(lhs.buf - rhs * sizeof(npy_ucs4),
760	                          lhs.after - lhs.buf + rhs * sizeof(npy_ucs4));
761	        case ENCODING::UTF8:
762	            char* buf = lhs.buf;
763	            buf = (char *)find_previous_utf8_character((unsigned char *)buf, rhs);
764	            return Buffer<enc>(buf, (npy_int64)(lhs.after - buf));
765	    }
