817	/*
818	 * Helper to fixup start/end slice values.
819	 *
820	 * This function is taken from CPython's unicode module
821	 * (https://github.com/python/cpython/blob/0b718e6407da65b838576a2459d630824ca62155/Objects/bytes_methods.c#L495)
822	 * in order to remain compatible with how CPython handles
823	 * start/end arguments to str function like find/rfind etc.
824	 */
825	static inline void
826	adjust_offsets(npy_int64 *start, npy_int64 *end, size_t len)
827	{
828	    if (*end > static_cast<npy_int64>(len)) {
829	        *end = len;
830	    }
831	    else if (*end < 0) {
832	        *end += len;
833	        if (*end < 0) {
834	            *end = 0;
835	        }
836	    }
837	
838	    if (*start < 0) {
839	        *start += len;
840	        if (*start < 0) {
841	            *start = 0;
842	        }
843	    }
844	}
