861	    char *start_loc = NULL;
862	    char *end_loc = NULL;
863	    if (enc == ENCODING::UTF8) {
864	        find_start_end_locs(buf1.buf, (buf1.after - buf1.buf), start, end,
865	                            &start_loc, &end_loc);
866	    }
867	    else {
868	        start_loc = (buf1 + start).buf;
869	        end_loc = (buf1 + end).buf;
