871	
872	    if (len2 == 1) {
873	        npy_intp result;
874	        switch (enc) {
875	            case ENCODING::UTF8:
876	            {
877	                if (num_bytes_for_utf8_character((const unsigned char *)buf2.buf) > 1) {
878	                    goto multibyte_search;
879	                }
880	                // fall through to the ASCII case because this is a one-byte character
881	            }
882	            case ENCODING::ASCII:
883	            {
884	                char ch = *buf2;
885	                CheckedIndexer<char> ind(start_loc, end_loc - start_loc);
886	                result = (npy_intp) find_char(ind, end_loc - start_loc, ch);
887	                if (enc == ENCODING::UTF8 && result > 0) {
888	                    result = utf8_character_index(
889	                            start_loc, start_loc - buf1.buf, start, result,
890	                            buf1.after - start_loc);
