1058	/*
1059	 * Count the number of occurrences of buf2 in buf1 between
1060	 * start (inclusive) and end (exclusive)
1061	 */
1062	template <ENCODING enc>
1063	static inline npy_intp
1064	string_count(Buffer<enc> buf1, Buffer<enc> buf2, npy_int64 start, npy_int64 end)
1065	{
1066	    size_t len1 = buf1.num_codepoints();
1067	    size_t len2 = buf2.num_codepoints();
1068	
1069	    adjust_offsets(&start, &end, len1);
1070	    if (end < start || end - start < static_cast<npy_int64>(len2)) {
1071	        return (npy_intp) 0;
1072	    }
1073	
1074	    if (len2 == 0) {
1075	        return (end - start) < PY_SSIZE_T_MAX ? end - start + 1 : PY_SSIZE_T_MAX;
1076	    }
1077	
1078	    char *start_loc = NULL;
1079	    char *end_loc = NULL;
1080	    if (enc == ENCODING::UTF8) {
1081	        find_start_end_locs(buf1.buf, (buf1.after - buf1.buf), start, end,
1082	                            &start_loc, &end_loc);
1083	    }
1084	    else {
1085	        start_loc = (buf1 + start).buf;
1086	        end_loc = (buf1 + end).buf;
1087	    }
1088	    npy_intp count = 0;
1089	    switch (enc) {
1090	        case ENCODING::UTF8:
1091	            count = fastsearch(start_loc, end_loc - start_loc, buf2.buf,
1092	                               buf2.after - buf2.buf, PY_SSIZE_T_MAX,
1093	                               FAST_COUNT);
1094	            break;
1095	        case ENCODING::ASCII:
1096	            count = (npy_intp) fastsearch(start_loc, end - start, buf2.buf, len2,
1097	                                          PY_SSIZE_T_MAX, FAST_COUNT);
1098	            break;
1099	        case ENCODING::UTF32:
1100	            count = (npy_intp) fastsearch((npy_ucs4 *)start_loc, end - start,
1101	                                          (npy_ucs4 *)buf2.buf, len2,
1102	                                          PY_SSIZE_T_MAX, FAST_COUNT);
1103	            break;
1104	    }
1105	    if (count < 0) {
1106	        return 0;
1107	    }
1108	    return count;
1109	}
