1115	template <ENCODING enc>
1116	inline npy_bool
1117	tailmatch(Buffer<enc> buf1, Buffer<enc> buf2, npy_int64 start, npy_int64 end,
1118	          STARTPOSITION direction)
1119	{
1120	    size_t len1 = buf1.num_codepoints();
1121	    size_t len2 = buf2.num_codepoints();
1122	
1123	    adjust_offsets(&start, &end, len1);
1124	    end -= len2;
1125	    if (end < start) {
1126	        return 0;
1127	    }
1128	
1129	    if (len2 == 0) {
1130	        return 1;
1131	    }
1132	
1133	    size_t offset;
1134	    size_t end_sub = len2 - 1;
1135	    if (direction == STARTPOSITION::BACK) {
1136	        offset = end;
1137	    }
1138	    else {
1139	        offset = start;
1140	    }
1141	
1142	    size_t size2 = len2;
1143	    if (enc == ENCODING::UTF8) {
1144	        size2 = (buf2.after - buf2.buf);
1145	    }
1146	
1147	    Buffer start_buf = (buf1 + offset);
1148	    Buffer end_buf = start_buf + end_sub;
1149	    if (*start_buf == *buf2 && *end_buf == *(buf2 + end_sub)) {
1150	        return !start_buf.buffer_memcmp(buf2, size2);
1151	    }
1152	
1153	    return 0;
1154	}
