1161	template <ENCODING enc>
1162	static inline size_t
1163	string_lrstrip_whitespace(Buffer<enc> buf, Buffer<enc> out, STRIPTYPE strip_type)
1164	{
1165	    size_t len = buf.num_codepoints();
1166	    if (len == 0) {
1167	        if (enc != ENCODING::UTF8) {
1168	            out.buffer_fill_with_zeros_after_index(0);
1169	        }
1170	        return 0;
1171	    }
1172	
1173	    size_t new_start = 0;
1174	
1175	    size_t num_bytes = (buf.after - buf.buf);
1176	    Buffer traverse_buf = Buffer<enc>(buf.buf, num_bytes);
1177	
1178	    if (strip_type != STRIPTYPE::RIGHTSTRIP) {
1179	        while (new_start < len) {
1180	            if (!traverse_buf.first_character_isspace()) {
1181	                break;
1182	            }
1183	            num_bytes -= traverse_buf.num_bytes_next_character();
1184	            new_start++;
1185	            traverse_buf++;  // may go one beyond buffer
1186	        }
1187	    }
1188	
1189	    size_t new_stop = len;  // New stop is a range (beyond last char)
1190	    if (enc == ENCODING::UTF8) {
1191	        traverse_buf = Buffer<enc>(buf.after, 0) - 1;
1192	    }
1193	    else {
1194	        traverse_buf = buf + (new_stop - 1);
1195	    }
1196	
1197	    if (strip_type != STRIPTYPE::LEFTSTRIP) {
1198	        while (new_stop > new_start) {
1199	            if (!traverse_buf.first_character_isspace() &&
1200	                    (enc == ENCODING::UTF8 || *traverse_buf != 0)) {
1201	                break;
1202	            }
1203	
1204	            num_bytes -= traverse_buf.num_bytes_next_character();
1205	            new_stop--;
1206	
1207	            // Do not step to character -1: can't find it's start for utf-8.
1208	            if (new_stop > 0) {
1209	                traverse_buf--;
1210	            }
1211	        }
1212	    }
1213	
1214	    Buffer offset_buf = buf + new_start;
1215	    if (enc == ENCODING::UTF8) {
1216	        offset_buf.buffer_memcpy(out, num_bytes);
1217	        return num_bytes;
1218	    }
1219	    offset_buf.buffer_memcpy(out, new_stop - new_start);
1220	    out.buffer_fill_with_zeros_after_index(new_stop - new_start);
1221	    return new_stop - new_start;
1222	}
