1565	static inline npy_intp
1566	string_pad(Buffer<enc> buf, npy_int64 width, npy_ucs4 fill, JUSTPOSITION pos, Buffer<enc> out)
1567	{
1568	    size_t final_width = width > 0 ? width : 0;
1569	    if (final_width > PY_SSIZE_T_MAX) {
1570	        npy_gil_error(PyExc_OverflowError, "padded string is too long");
1571	        return -1;
1572	    }
1573	
1574	    size_t len_codepoints = buf.num_codepoints();
1575	    size_t len_bytes = buf.after - buf.buf;
1576	
1577	    size_t len;
1578	    if (enc == ENCODING::UTF8) {
1579	        len = len_bytes;
1580	    }
1581	    else {
1582	        len = len_codepoints;
1583	    }
1584	
1585	    if (len_codepoints >= final_width) {
1586	        buf.buffer_memcpy(out, len);
1587	        return (npy_intp) len;
1588	    }
1589	
1590	    size_t left, right;
1591	    if (pos == JUSTPOSITION::CENTER) {
1592	        size_t pad = final_width - len_codepoints;
1593	        left = pad / 2 + (pad & final_width & 1);
1594	        right = pad - left;
1595	    }
1596	    else if (pos == JUSTPOSITION::LEFT) {
1597	        left = 0;
1598	        right = final_width - len_codepoints;
1599	    }
1600	    else {
1601	        left = final_width - len_codepoints;
1602	        right = 0;
1603	    }
1604	
1605	    assert(left >= 0 || right >= 0);
1606	    assert(left <= PY_SSIZE_T_MAX - len && right <= PY_SSIZE_T_MAX - (left + len));
1607	
1608	    if (left > 0) {
1609	        out.advance_chars_or_bytes(out.buffer_memset(fill, left));
1610	    }
1611	
1612	    buf.buffer_memcpy(out, len);
1613	    out += len_codepoints;
1614	
1615	    if (right > 0) {
1616	        out.advance_chars_or_bytes(out.buffer_memset(fill, right));
1617	    }
1618	
1619	    return final_width;
