1650	string_partition(Buffer<enc> buf1, Buffer<enc> buf2, npy_int64 idx,
1651	                 Buffer<enc> out1, Buffer<enc> out2, Buffer<enc> out3,
1652	                 npy_intp *final_len1, npy_intp *final_len2, npy_intp *final_len3,
