1662	        npy_gil_error(PyExc_ValueError, "empty separator");
1663	        *final_len1 = *final_len2 = *final_len3 = -1;
1664	        return;
1665	    }
1666	
1667	    if (idx < 0) {
1668	        if (pos == STARTPOSITION::FRONT) {
1669	            buf1.buffer_memcpy(out1, len1);
1670	            *final_len1 = len1;
1671	            *final_len2 = *final_len3 = 0;
1672	        }
1673	        else {
1674	            buf1.buffer_memcpy(out3, len1);
1675	            *final_len1 = *final_len2 = 0;
1676	            *final_len3 = len1;
1677	        }
1678	        return;
1679	    }
1680	
1681	    buf1.buffer_memcpy(out1, idx);
1682	    *final_len1 = idx;
1683	    buf2.buffer_memcpy(out2, len2);
1684	    *final_len2 = len2;
1685	    (buf1 + idx + len2).buffer_memcpy(out3, len1 - idx - len2);
